#include<bits/stdc++.h>
using namespace std;
#define ll long long
const int N=505;
int n,m,dfn[N],low[N],cnt,vis[N],vis2[N],cnt2,tmp,num,sum1,sum2;
vector<int> g[N];
void tarjan(int u,int f)
{
	low[u]=dfn[u]=++cnt;
	for(int i=0;i<g[u].size();i++)
	{
		int v=g[u][i];
		if(v==f) continue;
		if(!dfn[v])
		{
			tarjan(v,u);
			low[u]=min(low[u],low[v]);
			if(low[v]>=dfn[u])
			{
				if(u!=tmp) vis2[u]=1;
				else cnt2++;
			}
		}
		else
		{
			low[u]=min(low[u],dfn[v]);
		}
	}
}
void dfs(int u,int num)
{
	vis[u]=num;
	sum1++;
	for(int i=0;i<g[u].size();i++)
	{
		int v=g[u][i];
		if(vis2[v]&&vis[v]!=num)
		{
			sum2++;
			vis[v]=num;
		}
		if(!vis[v]) dfs(v,num);
	}
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
	while(cin>>m)
	{
		if(m==0) return 0;
		for(int i=1;i<=n;i++) g[i].clear();
		n=0;
		for(int i=1;i<=m;i++)
		{
			int u,v;
			cin>>u>>v;
			n=max(n,max(u,v));
			g[u].push_back(v);
			g[v].push_back(u);
		}
		memset(dfn,0,sizeof(dfn));
		memset(vis2,0,sizeof(vis2));
		memset(vis,0,sizeof(vis));
		memset(low,0,sizeof(low));
		cnt=0;
		for(int i=1;i<=n;i++)
		{
			if(!dfn[i])
			{
				cnt2=0;
				tmp=i;
				tarjan(i,0);
//				cout<<i<<" "<<cnt2<<"\n";
				if(cnt2>=2)
				{
					vis2[i]=1;
				}
			}
		}
//		for(int i=1;i<=n;i++) cout<<vis2[i]<<" ";
//		cout<<"\n";
		ll ans1=0,ans2=1;
		for(int i=1;i<=n;i++)
		{
			if(!vis[i]&&!vis2[i])
			{
				sum1=sum2=0;
				dfs(i,i);
				if(sum2==0)
				{
					ans1+=2;
					ans2*=((sum1-1)*sum1/2);
				}
				if(sum2==1)
				{
					ans1+=1;
					ans2*=sum1;
				}
			}
		}
		cout<<"Case "<<++num<<": "<<ans1<<" "<<ans2<<"\n";
	}
	return 0;
}
